### 2. Frontend: Streaming CoT Display (`ide_cot_bridge.js`)

Add this to your IDE to show thoughts as they arrive, preventing the "empty response" UI freeze:

```javascript
// RawrXD CoT Streaming Renderer
class CoTStream {
    constructor(containerId) {
        this.container = document.getElementById(containerId);
        this.steps = [];
    }
    
    async process(userInput, model = 'bigdaddyg-fast:latest') {
        this.container.innerHTML = '<div class="cot-loading">🧠 Initializing chain...</div>';
        
        try {
            const response = await fetch('/api/cot', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({message: userInput, model})
            });
            
            const data = await response.json();
            this.render(data);
            return data.final_answer;
            
        } catch (e) {
            this.container.innerHTML = `<div class="cot-error">Chain failed: ${e.message}</div>`;
            return userInput; // Fallback: echo user input
        }
    }
    
    render(data) {
        if (data.trivial) {
            this.container.innerHTML = `<div class="cot-skip">⚡ Fast response (greeting detected)</div>`;
            return;
        }
        
        let html = '<div class="cot-pipeline">';
        data.steps.forEach((step, idx) => {
            const icon = step.role === 'Critic' ? '🧐' : step.role === 'Auditor' ? '🛡' : '✅';
            const time = step.latency_ms ? `${step.latency_ms}ms` : '';
            const content = step.content 
                ? step.content.replace(/\n/g, '<br>') 
                : '<em>[Empty response recovered]</em>';
            
            html += `
                <div class="cot-step" style="animation-delay: ${idx * 0.1}s">
                    <div class="cot-header">
                        <span class="cot-icon">${icon}</span>
                        <span class="cot-role">${step.role}</span>
                        <span class="cot-model">${step.model}</span>
                        <span class="cot-time">${time}</span>
                    </div>
                    <div class="cot-content">${content}</div>
                </div>
            `;
        });
        
        html += `<div class="cot-final">✅ Final Answer (${data.total_ms}ms)</div>`;
        html += '</div>';
        
        this.container.innerHTML = html;
    }
}

// Usage in your chat handler:
